import{_ as r,c as i,o as t,ag as e}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"DGrid 제네시스 멤버십 구매 및 활성화 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"kr/Purchase-&-Activation.md","filePath":"kr/Purchase-&-Activation.md"}'),o={name:"kr/Purchase-&-Activation.md"};function l(d,a,n,s,c,h){return t(),i("div",null,a[0]||(a[0]=[e('<h1 id="dgrid-제네시스-멤버십-구매-및-활성화-가이드" tabindex="-1">DGrid 제네시스 멤버십 구매 및 활성화 가이드 <a class="header-anchor" href="#dgrid-제네시스-멤버십-구매-및-활성화-가이드" aria-label="Permalink to &quot;DGrid 제네시스 멤버십 구매 및 활성화 가이드&quot;">​</a></h1><p>더 많은 커뮤니티 회원이 편리하게 참여할 수 있도록 DGrid는 제네시스 멤버십 구독 절차를 간소화했다. 아래 단계를 따르면 구매를 완료하고 전용 혜택을 활성화할 수 있다.</p><h3 id="단계-1-dgrid-제네시스-패스-구매" tabindex="-1">단계 1: DGrid 제네시스 패스 구매 <a class="header-anchor" href="#단계-1-dgrid-제네시스-패스-구매" aria-label="Permalink to &quot;단계 1: DGrid 제네시스 패스 구매&quot;">​</a></h3><ol><li>​<strong>공식 민팅 페이지 방문</strong>​: 브라우저를 열고 URL <a href="https://premium.dgrid.ai/dgridpass?code=LXX9BB" target="_blank" rel="noreferrer">https://premium.dgrid.ai/dgridpass?code=LXX9BB</a>에 접속하여 제네시스 패스 구매 페이지로 이동한다.</li><li>​<strong>지갑 연결</strong>​: 페이지의 「지갑 연결」 버튼을 클릭하고 BNB 스마트 체인을 지원하는 지갑(예: MetaMask, Token Pocket, Binance Wallet, OKX Wallet)을 선택한 뒤, 지갑 연결 및 거래 권한 부여를 완료한다.</li><li>구매하려는 제네시스 패스 개수를 선택한다. 주문 정보가 정확한지 확인한 후 USDT로 결제를 완료한다.</li><li>DGrid 제네시스 패스 구매 약관을 읽고 동의한다.</li><li>초대 코드를 입력하고 구매를 완료하면 DGrid 제네시스 패스(NFT 증빙서류)를 성공적으로 획득할 수 있다.</li></ol><h3 id="단계-2-제네시스-멤버십-혜택-활성화" tabindex="-1">단계 2: 제네시스 멤버십 혜택 활성화 <a class="header-anchor" href="#단계-2-제네시스-멤버십-혜택-활성화" aria-label="Permalink to &quot;단계 2: 제네시스 멤버십 혜택 활성화&quot;">​</a></h3><ol><li>제네시스 패스 NFT를 보유한 후 DGrid 대시보드에 로그인하고 <strong>「제네시스 멤버십 혜택 활성화」</strong> 버튼을 찾는다.</li><li>화면의 안내에 따라 활성화 절차를 완료하면 제네시스 멤버십 전용 혜택이 모두 잠금 해제되고, 즉시 $DGAI &amp; $IOTX 듀얼 보상을 받기 시작할 수 있다.</li></ol><h3 id="단계-3-보상-및-혜택-사용-현황-모니터링" tabindex="-1">단계 3: 보상 및 혜택 사용 현황 모니터링 <a class="header-anchor" href="#단계-3-보상-및-혜택-사용-현황-모니터링" aria-label="Permalink to &quot;단계 3: 보상 및 혜택 사용 현황 모니터링&quot;">​</a></h3><ol><li>DGrid 대시보드를 통해 $DGAI 및 $IOTX 보상의 실시간 누적 현황을 확인할 수 있다.</li><li>대시보드에서는 보상 출금, 혜택 사용 통계 등 기능을 통해 개인 자산을 투명하게 관리할 수 있으며, 언제든지 혜택 동향을 파악할 수 있다.</li></ol><blockquote><p>​<strong>참고​</strong>​: DGrid 제네시스 멤버십 프로그램은 <strong>2026년 1월 1일 UTC 시간 00:00</strong>에 공식 출시되었다. 모든 혜택을 즉시 누릴 수 있도록 미리 구매 및 활성화 절차를 완료하는 것이 좋다.</p></blockquote>',9)]))}const g=r(o,[["render",l]]);export{p as __pageData,g as default};
